//refAssemblies: TCAdmin.Web.Shared.dll
using System;
using System.Linq;
using System.Threading.Tasks;
using TCAdmin.SDK.Constants;
using TCAdmin.Web.Shared.Models.Enums;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE

// Wipe on Rust Wipe Day.
// Runs as a scheduled task; only wipes when today is the first Thursday of the month.
// It stops the service (if running), runs the "Wipe Server" script, then restarts it.
//
// V2 called Script.Execute(gameId, 8) to run the wipe script by its numeric id. Script ids
// change on import, so V3 looks the wipe script up by name among the game's CustomServiceIcon
// scripts and runs it through the scripting environment.

async Task ReportProgress(string log)
{
    if (ThisTaskStepHandler != null)
        await ThisTaskStepHandler.UpdateProgress(log: log);
    else
        ScriptConsole.WriteLine(log);
}

// Determine the first Thursday of the current month.
var now = DateTime.Now;
var firstOfMonth = new DateTime(now.Year, now.Month, 1);
var offset = ((int)DayOfWeek.Thursday - (int)firstOfMonth.DayOfWeek + 7) % 7;
var firstThursday = firstOfMonth.AddDays(offset);

if (now.Date != firstThursday.Date)
{
    await ReportProgress("[Rust Wipe Script] Not wiping server as today is not the first Thursday of the month");
    return;
}

// Stop the service first so the wipe touches no open files. Remember whether it was running
// so we can bring it back afterwards.
var wasRunning = ThisService.Status == EServiceStatus.Started;
if (wasRunning)
{
    await ReportProgress("Service is running. Stopping the service...");
    await ServiceManagerService.StopService(ThisService.ServiceId);
}

// Find and run the "Wipe Server" script bound to this game.
var iconScripts = await ServiceManager.GetScripts(ThisService, GameScriptEvents.CustomServiceIcon);
var wipeScript = iconScripts.FirstOrDefault(s =>
    string.Equals(s.Name, "Wipe Server", StringComparison.OrdinalIgnoreCase));

if (wipeScript == null)
{
    await ReportProgress("[Rust Wipe Script] Could not find the 'Wipe Server' script to execute.");
}
else
{
    var result = await ScriptingEnvironment.ExecuteScript(ThisService, wipeScript, null, ThisCancellationToken);
    if (!result.Success)
        await ReportProgress($"[Rust Wipe Script] Wipe Server script reported an error: {result.Error?.Message}");
}

// Start the service again if it was running before the wipe.
if (wasRunning)
{
    await ReportProgress("Starting service...");
    await ServiceManagerService.StartService(ThisService.ServiceId);
    await ReportProgress("Service was started successfully.");
}

using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE

// Combine settings files (BeforeServiceStarted).
// Merges settings.cfg + additionalsettings.cfg into server.cfg, removes duplicate lines
// (preserving first-seen order) and prepends a "do not edit" warning to the first line.

var cfgDir = Path.Combine(ThisService.RootDirectory, "server", "my_server_identity", "cfg");
var settingsFile = Path.Combine(cfgDir, "settings.cfg");
var additionalSettingsFile = Path.Combine(cfgDir, "additionalsettings.cfg");
var serverCfgFile = Path.Combine(cfgDir, "server.cfg");

// Only include files that actually exist, in order.
var files = new[] { settingsFile, additionalSettingsFile }.Where(File.Exists).ToList();
if (files.Count == 0)
{
    ScriptConsole.WriteLine("No settings.cfg or additionalsettings.cfg found. Nothing to combine.");
    return;
}

// Read all lines from each file in order, de-duplicating while keeping first-seen order.
var seen = new HashSet<string>();
var settings = new List<string>();
foreach (var file in files)
{
    foreach (var line in await File.ReadAllLinesAsync(file, ThisCancellationToken))
    {
        if (seen.Add(line))
            settings.Add(line);
    }
}

if (settings.Count == 0)
{
    ScriptConsole.WriteLine("Settings files were empty. Nothing written.");
    return;
}

// Prepend the warning to the first content line (mirrors the V2 behaviour).
settings[0] = "#Do not update this file manually. Use settings.cfg or additionalsettings.cfg instead.\n" + settings[0];

await File.WriteAllTextAsync(serverCfgFile, string.Join("\n", settings), ThisCancellationToken);
ScriptConsole.WriteLine($"Combined {files.Count} settings file(s) into server.cfg.");

//refAssemblies: TCAdmin.Web.Shared.dll
using System;
using System.IO;
using TCAdmin.Web.Shared.Models.Enums;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE

// Move logfile (BeforeServiceStarted).
// Archives logs/latest.log to a timestamped server_<date>.log before the server starts so
// each run keeps its own log. Creates the logs directory if missing and (on a Linux host)
// fixes the directory owner so the impersonated game user can write to it.

var logDir = Path.Combine(ThisService.RootDirectory, "logs");
if (!Directory.Exists(logDir))
{
    Directory.CreateDirectory(logDir);
    // The owner fixup is a server-box concern; only meaningful when the host runs Linux.
    if (ThisServer.OperatingSystem == EOperatingSystem.Linux)
        OperatingSystem.SetDirectoryOwnerAutoDetect(logDir, false);
}

var logFile = Path.Combine(logDir, "latest.log");
if (!File.Exists(logFile))
{
    ScriptConsole.WriteLine("No latest.log to archive.");
    return;
}

// V2 used ThisService.StartTime (the previous run's start). It can be null before the first
// start, so fall back to now.
var lastStarted = ThisService.StartTime ?? DateTime.Now;
var timeFormat = $"{lastStarted.Year}-{lastStarted.Month}-{lastStarted.Day}__{lastStarted.Hour}-{lastStarted.Minute}-{lastStarted.Second}";
var newLogFileName = $"server_{timeFormat}.log";
var destination = Path.Combine(logDir, newLogFileName);

File.Move(logFile, destination);
ScriptConsole.WriteLine($"Archived latest.log to {newLogFileName}.");

using System;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE

// Switch update branch (Staging / Public). Bound to CustomServiceIcon.
// In V2 the popup field set ThisService.Variables['branch'] and the script called
// ThisService.Save(). V3 has no GameService.Save(); the platform already writes the
// chosen value into ThisService.Variables before the script runs (VerifyInputVariables),
// so we persist the service via the manager and report the selection.

var branch = ThisService.Variables.Parse<string>("branch");

await ServiceManager.UpdateAsync(ThisService, true, ThisCancellationToken);

ScriptConsole.WriteLine($"Branch switched to {branch}. Please run the Steam Update to update the server.");

//refAssemblies: TCAdmin.Web.Shared.dll, Microsoft.EntityFrameworkCore.dll
using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Text.RegularExpressions;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;
using TCAdmin.SDK.Database.Entities;
using TCAdmin.Web.Shared.Models.Enums;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE

// Wipe Server (CustomServiceIcon / ScheduledTask).
// Wipes the selected combination of map / players / additional files and optionally rolls a new
// seed. Each section is gated by a service variable the popup (or scheduled step) sets.
//
// Notable V2 -> V3 changes:
//  * The manual SteamCmd subprocess + Before/AfterSteamUpdate event scripts are replaced by
//    GameServiceManager.RunServiceSteamUpdate, which runs the update and fires those events itself.
//  * ThisService.Configure()/Save() are gone; service variable changes persist via
//    ServiceManager.UpdateAsync.
//  * Seed-list "remove used seed" updates the recurring step's Variables directly (V3 stores them
//    as a clean JSON dictionary, not the V2 nested XML field).

async Task Report(string log)
{
    if (ThisTaskStepHandler != null)
        await ThisTaskStepHandler.UpdateProgress(log: log);
    else
        ScriptConsole.WriteLine(log);
}

var root = ThisService.RootDirectory;
var identityDir = Path.Combine(root, "server", "my_server_identity");
var cfgFile = Path.Combine(identityDir, "cfg", "settings.cfg");

string GetVar(string name) => ThisService.Variables.Parse<string>(name) ?? string.Empty;
bool IsTrue(string name) => string.Equals(GetVar(name), "true", StringComparison.OrdinalIgnoreCase);

// --- Steam update -----------------------------------------------------------------------------
if (IsTrue("PerformSteamUpdate"))
{
    await Report("[Starting] Update Server");
    try
    {
        var steamResult = await GameServiceManager.RunServiceSteamUpdate(ThisService.ServiceId, null, ThisCancellationToken);
        if (!steamResult.Success)
            await Report($"Steam update reported a problem: {steamResult.Message}");
    }
    catch (Exception ex)
    {
        await Report($"Something went wrong during Steam Update. Error: {ex.Message}");
    }
    await Report("[Complete] Update Server");
}

// --- Wipe map ---------------------------------------------------------------------------------
if (IsTrue("wipemap"))
{
    await Report("[Starting] Wipe Map");
    if (Directory.Exists(identityDir))
    {
        var mapFiles = Directory.GetFiles(identityDir, "*.sav*")
            .Concat(Directory.GetFiles(identityDir, "*.map*"));
        foreach (var f in mapFiles)
        {
            try
            {
                File.Delete(f);
                await Report($"Deleted savefile {f}");
            }
            catch (Exception ex)
            {
                await Report($"Could not delete {f}, error was: {ex.Message}");
            }
        }
    }
    await Report("[Complete] Wipe Map");
}

// --- New random seed --------------------------------------------------------------------------
// oldSize/newSize carry through to the cfg rewrite that runs after the CustomSeeds section.
string oldSize = null;
string newSize = null;

if (IsTrue("wipemapnewseed") && File.Exists(cfgFile))
{
    await Report("[Starting] New Seed");
    await Report("Specifying a new seed");
    var contents = await File.ReadAllTextAsync(cfgFile, ThisCancellationToken);
    var match = Regex.Match(contents, @"server.seed[ \t]*(?<oldseed>-?[0-9, \t]*)", RegexOptions.IgnoreCase);
    var oldSeed = match.Groups["oldseed"].Value;

    var newSeed = Random.Shared.Next(-2147483647, 2147483647).ToString();
    while (oldSeed == newSeed)
        newSeed = Random.Shared.Next(-2147483647, 2147483647).ToString();

    await Report($"New seed is {newSeed}");
    contents = contents.Replace($"server.seed {oldSeed}", $"server.seed {newSeed}");
    await File.WriteAllTextAsync(cfgFile, contents, ThisCancellationToken);
    await Report("[Complete] New Seed");
}

// --- Wipe players -----------------------------------------------------------------------------
if (IsTrue("wipeplayers"))
{
    await Report("[Starting] Wipe Playerdata and Blueprints");
    var userdataFolder = Path.Combine(root, "userdata");
    if (Directory.Exists(userdataFolder))
    {
        try
        {
            Directory.Delete(userdataFolder, true);
            await Report("Userdata wiped");
        }
        catch (Exception ex)
        {
            await Report($"Could not delete {userdataFolder}, error was: {ex.Message}");
        }
    }

    if (Directory.Exists(identityDir))
    {
        foreach (var f in Directory.GetFiles(identityDir, "*.db*"))
        {
            try
            {
                File.Delete(f);
                await Report($"File {f} was deleted successfully");
            }
            catch (Exception ex)
            {
                await Report($"Could not delete {f}, error was: {ex.Message}");
            }
        }
    }
    await Report("[Complete] Wipe Playerdata and Blueprints");
}

// --- Wipe additional files / folders ----------------------------------------------------------
var wipeFiles = GetVar("WipeFiles");
if (!string.IsNullOrEmpty(wipeFiles))
{
    await Report("[Starting] Wipe Additional Files/Folders");
    foreach (var raw in wipeFiles.Split('\n', '\r').Where(x => x.Length > 0))
    {
        var entry = raw.Trim();
        if (entry.Length == 0) continue;

        if (entry.EndsWith('/'))
        {
            // Folder
            var folder = Path.Combine(root, entry);
            if (Directory.Exists(folder))
            {
                try
                {
                    Directory.Delete(folder, true);
                    await Report($"Deleted folder {entry}");
                }
                catch (Exception)
                {
                    await Report($"Could not delete folder {entry}");
                }
            }
        }
        else if (entry.Contains('*'))
        {
            // Glob within its directory
            var combined = Path.Combine(root, entry);
            var dir = Path.GetDirectoryName(combined) ?? root;
            var pattern = Path.GetFileName(combined);
            if (Directory.Exists(dir))
            {
                foreach (var filePath in Directory.GetFiles(dir, pattern))
                {
                    try
                    {
                        await Report($"Deleting {filePath}");
                        File.Delete(filePath);
                        await Report($"Deleted file {filePath}");
                    }
                    catch (Exception)
                    {
                        await Report($"Could not delete file {filePath}");
                    }
                }
            }
        }
        else
        {
            // Single file
            var file = Path.Combine(root, entry);
            if (File.Exists(file))
            {
                try
                {
                    File.Delete(file);
                    await Report($"Deleted file {entry}");
                }
                catch (Exception)
                {
                    await Report($"Could not delete file {entry}");
                }
            }
        }
    }
    await Report("[Complete] Wipe Additional Files/Folders");
}

// --- Replace seed from the CustomSeeds list ---------------------------------------------------
var customSeeds = GetVar("CustomSeeds");
if (!string.IsNullOrEmpty(customSeeds) && File.Exists(cfgFile))
{
    await Report("[Starting] Replacing Seed");
    var seeds = customSeeds.Split('\n', '\r').Where(x => x.Trim().Length > 0).Select(x => x.Trim()).ToList();
    if (seeds.Count > 0)
    {
        var contents = await File.ReadAllTextAsync(cfgFile, ThisCancellationToken);
        var seedMatch = Regex.Match(contents, @"server.seed[ \t]*(?<oldseed>-?[0-9, \t]*)", RegexOptions.IgnoreCase);
        var oldSeed = seedMatch.Groups["oldseed"].Value;
        var chosen = seeds[Random.Shared.Next(seeds.Count)];

        // If RemoveUsedSeed is set, drop the chosen seed from the recurring step's stored list
        // (so it isn't reused next run) and from the service variable.
        if (string.Equals(GetVar("RemoveUsedSeed"), "True", StringComparison.OrdinalIgnoreCase))
        {
            seeds.Remove(chosen);
            var updatedSeeds = string.Join("\n", seeds);

            var recurringTaskId = ThisTask?.RecurringTaskId;
            if (recurringTaskId != null)
            {
                try
                {
                    var recurringTask = await RecurringTaskManager.TCAdminDbContext.RecurringTasks
                        .Include(x => x.Steps)
                        .FirstOrDefaultAsync(x => x.RecurringTaskId == recurringTaskId.Value, ThisCancellationToken);
                    var step = recurringTask?.Steps.OrderBy(x => x.RecurringStepId).FirstOrDefault();
                    if (step != null)
                    {
                        step.Variables["CustomSeeds"] = updatedSeeds;
                        await RecurringTaskManager.UpdateAsync(recurringTask, true, ThisCancellationToken);
                    }
                }
                catch (Exception ex)
                {
                    await Report($"Could not update recurring task seed list: {ex.Message}");
                }
            }
        }

        var newSeed = chosen;
        // A "seed:size" entry also sets the world size.
        if (chosen.Contains(':'))
        {
            var parts = chosen.Split(':');
            newSeed = parts[0];
            newSize = parts[1];
            await Report($"Setting new seed. Was {oldSeed}, now {newSeed}");
            var sizeMatch = Regex.Match(contents, @"server.worldsize[ \t]*(?<oldsize>-?[0-9, \t]*)", RegexOptions.IgnoreCase);
            oldSize = sizeMatch.Groups["oldsize"].Value;
            await Report($"Setting new world size. Was {oldSize}, now {newSize}");
            ThisService.Variables["mapsize"] = newSize;
        }

        // Persist the remaining seed list back to the service variable.
        ThisService.Variables["CustomSeeds"] = string.Join("\n", seeds);

        contents = contents.Replace($"server.seed {oldSeed}", $"server.seed {newSeed}");
        if (oldSize != null && newSize != null)
            contents = contents.Replace($"server.worldsize {oldSize}", $"server.worldsize {newSize}");
        await File.WriteAllTextAsync(cfgFile, contents, ThisCancellationToken);

        ThisService.Variables["seed"] = newSeed;
        await Report("[Complete] Replacing Seed");
    }
}

await Report("The task completed successfully");

// Persist any service variable changes (mapsize / seed / CustomSeeds).
await ServiceManager.UpdateAsync(ThisService, true, ThisCancellationToken);

//refAssemblies: TCAdmin.Web.Shared.dll
using System;
using System.IO;
using System.Net.Http;
using TCAdmin.SDK.Misc.Compression;
using TCAdmin.Web.Shared.Models.Enums;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE

// Update uMod (Oxide) after a Steam update (DownloadGameFiles event).
// Re-downloads the matching Oxide.Rust build and extracts it over the freshly-updated
// game files, but only if uMod is already installed (the 'oxide' folder exists).
//
// V2 chose the Windows vs Linux build from the HOST OS. That is wrong under V3 because a
// Rust server can run on a Linux box via Wine or a Windows box via WSL — the Oxide build
// must match the GAME's OS, so we key off ThisGame.OperatingSystem.

var root = ThisService.RootDirectory;
var oxideDir = Path.Combine(root, "oxide");
if (!Directory.Exists(oxideDir))
{
    ScriptConsole.WriteLine("uMod not installed.");
    return;
}

var zipPath = Path.Combine(root, "Oxide.Rust.zip");
if (File.Exists(zipPath))
    File.Delete(zipPath);

ScriptConsole.WriteLine("Found uMod installation... Updating uMod.");

var isWindowsGame = ThisGame.OperatingSystem == EOperatingSystem.Windows;
var branch = ThisService.Variables.Parse<string>("branch");

string url;
if (string.Equals(branch, "staging", StringComparison.OrdinalIgnoreCase))
{
    ScriptConsole.WriteLine("Staging branch detected");
    url = isWindowsGame
        ? "https://ci.appveyor.com/api/projects/oxidemod/oxide-rust/artifacts/Oxide.Rust-staging.zip?pr=false&branch=staging"
        : "https://ci.appveyor.com/api/projects/oxidemod/oxide-rust/artifacts/Oxide.Rust-linux-staging.zip?pr=false&branch=staging";
}
else
{
    url = isWindowsGame
        ? "https://umod.org/games/rust/download"
        : "https://umod.org/games/rust/download/develop";
}

ScriptConsole.WriteLine($"Downloading file {zipPath} from {url}...");
using (var httpClient = new HttpClient())
{
    httpClient.Timeout = TimeSpan.FromMinutes(5);
    await using var stream = await httpClient.GetStreamAsync(url, ThisCancellationToken);
    await using var fileStream = File.Create(zipPath);
    await stream.CopyToAsync(fileStream, ThisCancellationToken);
}

if (!File.Exists(zipPath))
{
    ScriptConsole.WriteLine("Download failed - Oxide.Rust.zip was not created.");
    return;
}

// Stop the service before overwriting binaries if it is running.
if (ThisService.Status == EServiceStatus.Started)
{
    ScriptConsole.WriteLine("Stopping the service.");
    await ServiceManagerService.StopService(ThisService.ServiceId);
}

var compressionTools = new CompressionTools(OperatingSystem);
compressionTools.Decompress(zipPath, root, ThisCancellationToken);
File.Delete(zipPath);
ScriptConsole.WriteLine("uMod updated successfully.");

//refAssemblies: TCAdmin.Web.Shared.dll, OpenGSQ.dll
using System;
using System.Text.RegularExpressions;
using OpenGSQ.Protocols;
using OpenGSQ.Responses.Source;
using TCAdmin.SDK.Hubs.Models.GameQuery;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE

// Custom query protocol (bound to CustomQueryProtocol).
//
// V2 returned a qstat-style XML string. V3's custom_script provider instead JSON-serializes the
// script's ReturnValue and deserializes it into a GameQueryResponse (see
// CustomScriptQuery.cs), so we build and return that object directly with the same data the
// V2 XML carried: name, gametype, map, players, rules and the game_tag cp/mp override.
//
// The provider injects Address/Port for the service being queried. At runtime, injected script
// variables are read via Dynamic.X -- bare identifiers are only auto-rewritten to Dynamic.X by the
// editor's syntax checker, not by the execution path, so they must be qualified here.
string address = Convert.ToString(Dynamic.Address);
if (string.IsNullOrEmpty(address)) address = ThisService.IPAddress;
int port = Convert.ToInt32(Dynamic.Port);
if (port <= 0) port = ThisService.QueryPort;

try
{
    // Rust answers the Source (A2S) query protocol.
    var source = new Source(address, port, 5000);
    var info = await source.GetInfo();
    var players = await source.GetPlayers();
    var rules = await source.GetRules();

    var response = new GameQueryResponse
    {
        Success = true,
        Status = "online",
        Protocol = "custom_script",
        Address = address,
        Hostname = $"{address}:{port}",
        Name = info.Name,
        GameType = info.Game,
        Map = info.Map,
        NumPlayers = info.Players,
        MaxPlayers = info.MaxPlayers,
        NumSpectators = 0,
        MaxSpectators = 0,
        Retries = 0
    };

    if (rules != null)
    {
        foreach (var rule in rules)
            response.Rules[rule.Key] = rule.Value;
    }

    if (players != null)
    {
        foreach (var player in players)
        {
            response.Players.Add(new GameQueryPlayer
            {
                Name = player.Name,
                // Source A2S exposes Score and Duration but not a per-player ping.
                Score = (int)player.Score,
                Ping = 0
            });
        }
    }

    // Rust reports real player/slot counts in the "game tag" (A2S keywords), e.g. "cp12,mp50".
    // Prefer the game_tag rule, falling back to the A2S keywords field on the info packet.
    var gameTag = response.Rules.TryGetValue("game_tag", out var tagFromRules) && !string.IsNullOrEmpty(tagFromRules)
        ? tagFromRules
        : (info as SourceInfo)?.Keywords ?? string.Empty;

    if (!string.IsNullOrEmpty(gameTag))
    {
        var cp = Regex.Match(gameTag, @"cp(\d+)");
        if (cp.Success)
            response.NumPlayers = int.Parse(cp.Groups[1].Value);

        var mp = Regex.Match(gameTag, @"mp(\d+)");
        if (mp.Success)
            response.MaxPlayers = int.Parse(mp.Groups[1].Value);
    }

    Globals.ReturnValue = response;
}
catch (Exception ex)
{
    // Returning an offline response keeps the query subsystem happy when the server is down.
    Globals.ReturnValue = GameQueryResponse.DefaultOfflineResponse(address, "custom_script", ex.Message);
}

using System;
using System.Collections.Generic;
using System.Linq;

var Globals = new TCAdmin.Scripting.Engines.Addons.CSharpGameGlobals(); // DO NOT MODIFY THIS LINE

// Set default priority to idle and random core (BeforeServiceStarted, Linux only).
//
// Linux port of the Windows script of the same name. This event fires BEFORE the game process
// exists, so there is nothing to renice/taskset yet. Compute the random startup mask here and
// hand it to the companion "Set priority and affinity back to normal" (AfterServiceStarted)
// script via a service variable; that script applies idle priority + this mask to the live
// processes, then restores the configured values once the log reports "Server startup complete".

const int startCores = 4; // how many cores the service should start on

// NUMBER_OF_PROCESSORS - 1, mirroring the Windows/V2 calculation (which excludes the top core).
var coreCount = Environment.ProcessorCount - 1;
if (coreCount < 1)
{
    ScriptConsole.WriteLine("Not enough cores to compute a startup affinity mask.");
    return;
}

// Pick `startCores` distinct cores from 1..coreCount (V2 excluded core 0 / the top index) and OR
// their bits together. A core value c maps to affinity bit (c-1), exactly as the V2 bit-string math.
var candidates = Enumerable.Range(1, coreCount).ToList();
var take = Math.Min(startCores, candidates.Count);
var chosen = new List<int>();
while (chosen.Count < take)
{
    var pick = candidates[Random.Shared.Next(candidates.Count)];
    candidates.Remove(pick);
    chosen.Add(pick);
}

long affinityMask = 0;
foreach (var core in chosen)
    affinityMask |= 1L << (core - 1);

ThisService.Variables["__StartupAffinity"] = affinityMask.ToString();
await ServiceManager.UpdateAsync(ThisService, true, ThisCancellationToken);

ScriptConsole.WriteLine($"Computed startup affinity mask {affinityMask} (cores {string.Join(", ", chosen.OrderBy(x => x))}). " +
    "The 'Set priority and affinity back to normal' script will apply it on startup.");

