// priority on the random startup cores picked by "Set default priority to idle and random core",
// watch the log until "Server startup complete", then restore. Like the Windows version, the
// wait + restore run as a detached Task inside the Monitor process so this script returns right
// away and Start doesn't hold the power semaphore; the next Stop/Kill cancels
// ThisCancellationToken, which ends the watcher on its next poll (restore runs in a finally).
//
// Why this doesn't just use Process.PriorityClass / ProcessorAffinity like the Windows script:
// - nice and CPU affinity are PER-THREAD attributes on Linux. Those APIs only touch the main
//   thread; existing worker threads keep their values, and threads inherit from their creator.
//   The restore would leave every worker thread throttled forever. Instead: renice every tid in
//   /proc/<pid>/task, and `taskset -a` (= all threads) per pid, re-enumerating at restore time.
//   nice 19 = the SDK's own mapping for ProcessPriorityClass.Idle (see LinuxServiceControl).
// - The Monitor runs as root, so lowering nice back down (19 -> configured) is permitted.
// - The service's processes are found by executable-path-under-root (the Windows script's
//   FindProcesses(root) matches by executable path too; the IOperatingSystem Linux overload
//   matches bare exe names, so a /proc scan is done here instead). This naturally excludes the
//   ServiceIO wrapper and /usr/bin/bash start scripts, which never burn CPU anyway.
//
// LIMITATIONS:
// - Nothing pins priority on Linux (no Windows Job Object), so the restore returns to the
//   service's CONFIGURED priority/affinity instead of blindly Normal/all-cores — otherwise this
//   script would stomp an admin-configured priority or core mask.
// - If the service has cgroup limits (affinity/CPU/memory configured, or a Virtual Server core
//   partition), cpuset.cpus caps whatever taskset requests: masks are intersected, and a random
//   startup mask fully outside the cpuset fails harmlessly (the nice throttle still applies).
//
// Detached-task rules: after the script returns, only detached entities (ThisService, ThisGame),
// BCL APIs and captured locals may be used — the *Manager globals die with the scripting
// environment's DI scope, and ScriptConsole writes become silent no-ops.

var root = ThisService.RootDirectory.TrimEnd('/');

// Not a native Linux host (e.g. this Linux game deployed under WSL on a Windows node) —
// /proc, renice and taskset are unavailable there; nothing to throttle.
if (!Directory.Exists("/proc"))
{
    ScriptConsole.WriteLine("Host is not native Linux; skipping the startup priority/affinity throttle.");
    return;
}

// Startup mask handed over by "Set default priority to idle and random core" (0 = none/skip).
var startupMaskText = ThisService.Variables.Parse<string>("__StartupAffinity");
long.TryParse(startupMaskText, out var startupMask);

// Restore targets: the service's configured priority/affinity (see LIMITATIONS above).
var restoreNice = ThisService.Priority switch
{
    ProcessPriorityClass.RealTime => -20,
    ProcessPriorityClass.High => -11,
    ProcessPriorityClass.AboveNormal => -5,
    ProcessPriorityClass.BelowNormal => 5,
    ProcessPriorityClass.Idle => 19,
    _ => 0
};
var configuredAffinity = ThisService.Affinity.GetValueOrDefault();
var restoreMask = configuredAffinity > 0
    ? configuredAffinity
    : (Environment.ProcessorCount >= 64 ? -1L : (1L << Environment.ProcessorCount) - 1);

// Capture what the detached task needs into locals before the script returns.
var token = ThisCancellationToken;
var logFile = string.IsNullOrWhiteSpace(ThisGame.ConsoleConfig.LogFile)
    ? null
    : Path.Combine(root, ThisGame.ConsoleConfig.LogFile.Replace('\\', '/'));

string MaskToCpuList(long mask)
{
    var cpus = new List<int>();
    for (var cpu = 0; cpu < 64; cpu++)
        if ((mask & (1L << cpu)) != 0) cpus.Add(cpu);
    return string.Join(",", cpus);
}

void Run(string command, string arguments)
{
    try
    {
        var startInfo = new ProcessStartInfo(command, arguments)
        {
            UseShellExecute = false,
            RedirectStandardOutput = true,
            RedirectStandardError = true
        };
        using var process = Process.Start(startInfo);
        process?.WaitForExit(5000);
    }
    catch
    {
        // Tool missing or target process gone — skip.
    }
}

List<int> FindServicePids()
{
    var pids = new List<int>();
    foreach (var pidDir in Directory.GetDirectories("/proc"))
    {
        if (!int.TryParse(Path.GetFileName(pidDir), out var pid)) continue;
        try
        {
            var exe = File.ResolveLinkTarget(Path.Combine(pidDir, "exe"), false)?.FullName;
            if (exe != null && (exe.Equals(root, StringComparison.Ordinal) ||
                                exe.StartsWith(root + "/", StringComparison.Ordinal)))
            {
                pids.Add(pid);
            }
        }
        catch
        {
            // Kernel thread, already exited, or unreadable — skip.
        }
    }
    return pids;
}

void ApplyToServiceProcesses(int niceValue, long affinityMask)
{
    foreach (var pid in FindServicePids())
    {
        try
        {
            // nice is per-thread: renice every task of the process.
            var tids = Directory.GetDirectories($"/proc/{pid}/task")
                .Select(Path.GetFileName)
                .Where(t => !string.IsNullOrEmpty(t))
                .ToList();
            if (tids.Count > 0)
                Run("renice", $"-n {niceValue} -p {string.Join(" ", tids)}");

            // taskset -a applies the mask to all of the process's threads.
            if (affinityMask != 0)
                Run("taskset", $"-a -c -p {MaskToCpuList(affinityMask)} {pid}");
        }
        catch
        {
            // Process exited between enumeration and adjustment — skip it.
        }
    }
}

// Throttle synchronously so the server is already throttled when Start returns.
ApplyToServiceProcesses(19, startupMask);

if (logFile == null)
{
    // No log file configured — nothing to wait for.
    ApplyToServiceProcesses(restoreNice, restoreMask);
}
else
{
    _ = Task.Run(async () =>
    {
        try
        {
            var deadline = DateTime.UtcNow.AddMinutes(15);
            long lastLength = 0;
            var started = false;
            while (!started && DateTime.UtcNow < deadline && !token.IsCancellationRequested)
            {
                if (File.Exists(logFile))
                {
                    try
                    {
                        using var stream = new FileStream(logFile, FileMode.Open, FileAccess.Read, FileShare.ReadWrite);
                        if (stream.Length < lastLength) lastLength = 0; // log rotated/truncated
                        stream.Seek(lastLength, SeekOrigin.Begin);
                        using var reader = new StreamReader(stream);
                        var text = await reader.ReadToEndAsync(token);
                        lastLength = stream.Length;
                        if (text.IndexOf("Server startup complete", StringComparison.OrdinalIgnoreCase) >= 0)
                            started = true;
                    }
                    catch (OperationCanceledException) { throw; }
                    catch
                    {
                        // File momentarily unavailable (rotation) — try again on the next poll.
                    }
                }

                if (!started)
                    await Task.Delay(TimeSpan.FromSeconds(2), token);
            }
        }
        catch (OperationCanceledException)
        {
            // Stop/Kill during startup — fall through to the restore.
        }
        catch
        {
            // Never let an exception escape a detached task.
        }
        finally
        {
            // Restore even on cancellation: per-pid try/catch makes this a no-op when the
            // processes are already gone. The second pass catches threads spawned while the
            // first pass ran (they inherit the throttled nice from their creator thread).
            ApplyToServiceProcesses(restoreNice, restoreMask);
            await Task.Delay(500);
            ApplyToServiceProcesses(restoreNice, restoreMask);
        }
    });
}

ScriptConsole.WriteLine("Startup watcher detached; priority/affinity will be restored when the log reports startup complete.");
